import React, { useState, useEffect } from 'react';
import api from '../services/api';
import { useAuth } from '../context/AuthContext';

const Sports = () => {
  const [events, setEvents] = useState([]);
  const [betTicket, setBetTicket] = useState([]);
  const [betAmount, setBetAmount] = useState(10);
  const [betType, setBetType] = useState('single'); // 'single' ou 'multiple'
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);
  const [now, setNow] = useState(new Date());
  const { fetchBalance } = useAuth();

  useEffect(() => {
    loadEvents();
    const timer = setInterval(() => setNow(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const loadEvents = async () => {
    try {
      const res = await api.get('/api/sports/events');
      setEvents(res.data);
    } catch (err) {
      console.error('Erro ao carregar eventos');
    }
  };

  const addToTicket = (event, selection) => {
    setResult(null);
    const exists = betTicket.find(b => b.eventId === event.id);
    if (exists) {
      if (exists.selection === selection) {
        setBetTicket(betTicket.filter(b => b.eventId !== event.id));
      } else {
        setBetTicket(betTicket.map(b => b.eventId === event.id ? { ...b, selection } : b));
      }
    } else {
      setBetTicket([...betTicket, { eventId: event.id, eventName: `${event.team1} vs ${event.team2}`, selection, odd: event.odds[selection] }]);
    }
  };

  const calculateTotalOdd = () => {
    return betTicket.reduce((acc, b) => acc * b.odd, 1).toFixed(2);
  };

  const placeBet = async () => {
    if (betTicket.length === 0 || betAmount <= 0) return;
    setLoading(true);
    try {
      const res = await api.post('/api/sports/bet', {
        bets: betTicket,
        totalBet: parseFloat(betAmount),
        type: betType
      });
      setResult(res.data);
      fetchBalance();
      setBetTicket([]);
    } catch (err) {
      setResult({ message: err.response?.data?.message || 'Erro ao processar aposta' });
    } finally {
      setLoading(false);
    }
  };

  const getCountdown = (dateStr) => {
    const diff = new Date(dateStr) - now;
    if (diff <= 0) return 'EM ANDAMENTO';
    const hours = Math.floor(diff / 3600000);
    const minutes = Math.floor((diff % 3600000) / 60000);
    const seconds = Math.floor((diff % 60000) / 1000);
    return `${hours}h ${minutes}m ${seconds}s`;
  };

  const sportIcons = { Futebol: '⚽', Basquete: '🏀', Tênis: '🎾', MMA: '🥊' };

  const styles = {
    container: { maxWidth: '1200px', margin: '0 auto', padding: '20px', display: 'flex', gap: '20px', flexWrap: 'wrap' },
    mainContent: { flex: '1', minWidth: '300px' },
    ticketSidebar: { width: '350px', minWidth: '300px', background: '#1a1a1a', borderRadius: '16px', padding: '20px', border: '1px solid #2a2a2a', height: 'fit-content', position: 'sticky', top: '80px' },
    title: { fontFamily: "'Orbitron', sans-serif", fontSize: '28px', fontWeight: 700, marginBottom: '20px', color: '#fff' },
    eventCard: (isLive) => ({
      background: '#1a1a1a', border: isLive ? '1px solid #ff1744' : '1px solid #2a2a2a',
      borderRadius: '12px', padding: '15px', marginBottom: '12px', transition: 'all 0.3s'
    }),
    oddsGrid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(80px, 1fr))', gap: '8px', marginTop: '12px' },
    oddBtn: (active) => ({
      padding: '10px', borderRadius: '8px', border: 'none', cursor: 'pointer',
      background: active ? '#FFD700' : '#2a2a2a', color: active ? '#000' : '#fff',
      fontWeight: 700, fontSize: '13px', transition: '0.2s'
    }),
    ticketItem: { borderBottom: '1px solid #2a2a2a', padding: '10px 0', fontSize: '13px' },
    totalBox: { marginTop: '20px', padding: '15px', background: '#0a0a0a', borderRadius: '8px', border: '1px solid #FFD700' }
  };

  return (
    <div style={styles.container}>
      <div style={styles.mainContent}>
        <h1 style={styles.title}>🏆 <span className="gold-text">W.M ESPORTES</span></h1>

        {/* EVENTOS AO VIVO */}
        <h2 style={{ fontSize: '18px', color: '#ff1744', marginBottom: '15px', display: 'flex', alignItems: 'center', gap: '8px' }}>
          <span className="dot-live"></span> AO VIVO AGORA
        </h2>
        {events.filter(e => e.status === 'live').map(event => (
          <div key={event.id} style={styles.eventCard(true)}>
            <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '12px', color: '#888', marginBottom: '8px' }}>
              <span>{sportIcons[event.sport]} {event.league}</span>
              <span style={{ color: '#ff1744', fontWeight: 700 }}>LIVE</span>
            </div>
            <div style={{ fontSize: '16px', fontWeight: 700, textAlign: 'center', margin: '10px 0' }}>
              {event.team1} <span style={{ color: '#FFD700' }}>VS</span> {event.team2}
            </div>
            <div style={styles.oddsGrid}>
              {Object.entries(event.odds).map(([key, val]) => (
                <button key={key} style={styles.oddBtn(betTicket.find(b => b.eventId === event.id && b.selection === key))}
                  onClick={() => addToTicket(event, key)}>
                  <div style={{ fontSize: '10px', opacity: 0.7 }}>{key === 'team1Win' ? '1' : key === 'draw' ? 'X' : '2'}</div>
                  {val.toFixed(2)}
                </button>
              ))}
            </div>
          </div>
        ))}

        {/* PRÓXIMOS JOGOS */}
        <h2 style={{ fontSize: '18px', color: '#FFD700', margin: '30px 0 15px' }}>📅 PRÓXIMOS JOGOS</h2>
        {events.filter(e => e.status !== 'live').map(event => (
          <div key={event.id} style={styles.eventCard(false)}>
            <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '12px', color: '#888', marginBottom: '8px' }}>
              <span>{sportIcons[event.sport]} {event.league}</span>
              <span style={{ color: '#FFD700' }}>{getCountdown(event.date)}</span>
            </div>
            <div style={{ fontSize: '15px', fontWeight: 700, textAlign: 'center', margin: '8px 0' }}>
              {event.team1} <span style={{ color: '#DC0000' }}>VS</span> {event.team2}
            </div>
            <div style={styles.oddsGrid}>
              {Object.entries(event.odds).map(([key, val]) => (
                <button key={key} style={styles.oddBtn(betTicket.find(b => b.eventId === event.id && b.selection === key))}
                  onClick={() => addToTicket(event, key)}>
                  <div style={{ fontSize: '10px', opacity: 0.7 }}>{key === 'team1Win' ? '1' : key === 'draw' ? 'X' : '2'}</div>
                  {val.toFixed(2)}
                </button>
              ))}
            </div>
          </div>
        ))}
      </div>

      {/* BILHETE DE APOSTAS */}
      <div style={styles.ticketSidebar}>
        <h3 style={{ fontFamily: "'Orbitron', sans-serif", fontSize: '18px', color: '#FFD700', marginBottom: '15px' }}>🎟️ SEU BILHETE</h3>

        {betTicket.length === 0 ? (
          <p style={{ color: '#666', textAlign: 'center', padding: '20px' }}>Selecione um evento para começar a apostar</p>
        ) : (
          <>
            <div style={{ display: 'flex', gap: '5px', marginBottom: '15px' }}>
              <button onClick={() => setBetType('single')} style={{ flex: 1, padding: '8px', borderRadius: '4px', border: 'none', background: betType === 'single' ? '#FFD700' : '#2a2a2a', color: betType === 'single' ? '#000' : '#fff', fontSize: '12px', fontWeight: 700 }}>INDIVIDUAL</button>
              <button onClick={() => setBetType('multiple')} style={{ flex: 1, padding: '8px', borderRadius: '4px', border: 'none', background: betType === 'multiple' ? '#FFD700' : '#2a2a2a', color: betType === 'multiple' ? '#000' : '#fff', fontSize: '12px', fontWeight: 700 }}>MÚLTIPLA</button>
            </div>

            {betTicket.map(bet => (
              <div key={bet.eventId} style={styles.ticketItem}>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '4px' }}>
                  <span style={{ fontWeight: 700 }}>{bet.eventName}</span>
                  <button onClick={() => addToTicket({ id: bet.eventId }, bet.selection)} style={{ background: 'none', border: 'none', color: '#ff1744', cursor: 'pointer' }}>✕</button>
                </div>
                <div style={{ display: 'flex', justifyContent: 'space-between', color: '#888' }}>
                  <span>Seleção: {bet.selection === 'team1Win' ? 'Casa' : bet.selection === 'draw' ? 'Empate' : 'Fora'}</span>
                  <span style={{ color: '#FFD700', fontWeight: 700 }}>{bet.odd.toFixed(2)}</span>
                </div>
              </div>
            ))}

            <div style={styles.totalBox}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '10px' }}>
                <span>ODD TOTAL:</span>
                <span style={{ color: '#FFD700', fontWeight: 800 }}>{betType === 'multiple' ? calculateTotalOdd() : 'Indiv.'}</span>
              </div>
              <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '10px' }}>
                <span style={{ fontSize: '12px' }}>VALOR R$:</span>
                <input type="number" value={betAmount} onChange={(e) => setBetAmount(e.target.value)} style={{ background: '#1a1a1a', border: '1px solid #333', color: '#fff', padding: '5px', borderRadius: '4px', width: '80px' }} />
              </div>
              <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '16px', fontWeight: 800 }}>
                <span>RETORNO:</span>
                <span style={{ color: '#00c853' }}>R$ {betType === 'multiple' ? (betAmount * calculateTotalOdd()).toFixed(2) : (betAmount * (calculateTotalOdd() / betTicket.length)).toFixed(2)}</span>
              </div>
            </div>

            <button onClick={placeBet} disabled={loading} style={{ width: '100%', marginTop: '15px', padding: '15px', borderRadius: '8px', border: 'none', background: 'linear-gradient(135deg, #FFD700, #B8860B)', color: '#000', fontWeight: 800, cursor: 'pointer' }}>
              {loading ? 'PROCESSANDO...' : '💰 CONFIRMAR APOSTA'}
            </button>
          </>
        )}

        {result && (
          <div style={{ marginTop: '15px', padding: '15px', borderRadius: '8px', background: result.winAmount > 0 ? 'rgba(0,200,83,0.1)' : 'rgba(255,23,68,0.1)', border: `1px solid ${result.winAmount > 0 ? '#00c853' : '#ff1744'}`, textAlign: 'center' }}>
            <p style={{ color: result.winAmount > 0 ? '#00c853' : '#ff1744', fontWeight: 700 }}>{result.message}</p>
            {result.winAmount > 0 && <p style={{ fontSize: '20px', fontWeight: 800 }}>+ R$ {result.winAmount.toFixed(2)}</p>}
          </div>
        )}
      </div>

      <style>{`
        .dot-live { width: 8px; height: 8px; background: #ff1744; border-radius: 50%; display: inline-block; animation: blink 1s infinite; }
        @keyframes blink { 0% { opacity: 1; } 50% { opacity: 0.3; } 100% { opacity: 1; } }
        .gold-text { color: #FFD700; text-shadow: 0 0 10px rgba(255,215,0,0.3); }
      `}</style>
    </div>
  );
};

export default Sports;
